  t,
}: {
  typeKey?: AgentTypeKey;
  status: AgentRuntimeAvailability | undefined;
  isChecking: boolean;
  t?: (key: I18nKey) => string;
}): string {
  const fallback: Partial<Record<I18nKey, string>> = {
    'agent.status.available': 'Available',
